import sys
from typing import List

def solve(nums: List[int], queries: List[List[int]]) -> List[int]:
    # Precompute popcount-depth for numbers up to 1e15
    # Since the maximum popcount-depth for numbers up to 1e15 is 5 (as per the problem statement)
    # We can use memoization to store the depth for each number encountered

    depth_memo = {}

    def get_popcount_depth(x: int) -> int:
        if x in depth_memo:
            return depth_memo[x]
        original_x = x
        depth = 0
        while x != 1:
            x = bin(x).count('1')
            depth += 1
        depth_memo[original_x] = depth
        return depth

    # Precompute the depth for all initial nums
    depths = [get_popcount_depth(num) for num in nums]

    # Since k can be up to 5, we can maintain a segment tree or binary indexed tree (Fenwick tree)
    # for each possible k (0 to 5) to handle range queries and point updates efficiently

    class FenwickTree:
        def __init__(self, size):
            self.size = size
            self.tree = [0] * (self.size + 1)

        def update(self, index: int, delta: int) -> None:
            while index <= self.size:
                self.tree[index] += delta
                index += index & -index

        def query(self, index: int) -> int:
            res = 0
            while index > 0:
                res += self.tree[index]
                index -= index & -index
            return res

        def range_query(self, l: int, r: int) -> int:
            return self.query(r) - self.query(l - 1)

    # Initialize Fenwick trees for each k (0 to 5)
    max_k = 5
    fenwick_trees = [FenwickTree(len(nums)) for _ in range(max_k + 1)]

    # Initialize the Fenwick trees with the initial depths
    for idx in range(len(nums)):
        k = depths[idx]
        if k <= max_k:
            fenwick_trees[k].update(idx + 1, 1)

    answer = []

    for query in queries:
        if query[0] == 1:
            # Query type [1, l, r, k]
            l, r, k = query[1], query[2], query[3]
            if k > max_k:
                answer.append(0)
            else:
                res = fenwick_trees[k].range_query(l + 1, r + 1)
                answer.append(res)
        elif query[0] == 2:
            # Query type [2, idx, val]
            idx, val = query[1], query[2]
            old_k = depths[idx]
            new_k = get_popcount_depth(val)

            if old_k <= max_k:
                fenwick_trees[old_k].update(idx + 1, -1)
            if new_k <= max_k:
                fenwick_trees[new_k].update(idx + 1, 1)

            # Update nums and depths
            nums[idx] = val
            depths[idx] = new_k

    return answer
